mapper.select:
SELECT s.*, c.college_name, m.major_name, cl.class_name FROM edu_student s LEFT JOIN edu_college c ON s.college_id = c.id LEFT JOIN edu_major m ON s.major_id = m.id LEFT JOIN edu_class cl ON s.class_id = cl.id
AND s.student_no LIKE CONCAT('%', #{studentNo}, '%')
AND s.name LIKE CONCAT('%', #{name}, '%')
AND s.college_id = #{collegeId}
AND s.major_id = #{majorId}
AND s.class_id = #{classId}
AND s.enrollment_year = #{enrollmentYear}
AND s.status = #{status}
ORDER BY s.id DESC

